-- ================================================================
-- VHDL Sequential Logic Examples
-- ================================================================

-- 1. D Flip-Flop with Asynchronous Reset
library IEEE;
use IEEE.STD_LOGIC_1164.ALL;

entity dff_async_reset is
    Port (
        clk  : in  STD_LOGIC;
        rst  : in  STD_LOGIC;  -- active high async reset
        d    : in  STD_LOGIC;
        q    : out STD_LOGIC
    );
end dff_async_reset;

architecture Behavioral of dff_async_reset is
begin
    process(clk, rst)
    begin
        if rst = '1' then
            q <= '0';           -- Asynchronous reset
        elsif rising_edge(clk) then
            q <= d;             -- Capture D on rising clock edge
        end if;
    end process;
end Behavioral;

-- ---------------------------------------------------------------
-- 2. T Flip-Flop
-- ---------------------------------------------------------------
entity tff is
    Port (
        clk : in  STD_LOGIC;
        rst : in  STD_LOGIC;
        t   : in  STD_LOGIC;
        q   : out STD_LOGIC
    );
end tff;

architecture Behavioral of tff is
    signal q_reg : STD_LOGIC := '0';
begin
    process(clk, rst)
    begin
        if rst = '1' then
            q_reg <= '0';
        elsif rising_edge(clk) then
            if t = '1' then
                q_reg <= not q_reg;  -- Toggle
            end if;
        end if;
    end process;
    q <= q_reg;
end Behavioral;

-- ---------------------------------------------------------------
-- 3. JK Flip-Flop
-- ---------------------------------------------------------------
entity jkff is
    Port (
        clk : in  STD_LOGIC;
        rst : in  STD_LOGIC;
        j   : in  STD_LOGIC;
        k   : in  STD_LOGIC;
        q   : out STD_LOGIC
    );
end jkff;

architecture Behavioral of jkff is
    signal q_reg : STD_LOGIC := '0';
begin
    process(clk, rst)
    begin
        if rst = '1' then
            q_reg <= '0';
        elsif rising_edge(clk) then
            case (j & k) is
                when "01"   => q_reg <= '0';       -- Reset
                when "10"   => q_reg <= '1';       -- Set
                when "11"   => q_reg <= not q_reg; -- Toggle
                when others => null;                -- Hold
            end case;
        end if;
    end process;
    q <= q_reg;
end Behavioral;

-- ---------------------------------------------------------------
-- 4. 4-bit Synchronous Counter
-- ---------------------------------------------------------------
library IEEE;
use IEEE.STD_LOGIC_1164.ALL;
use IEEE.STD_LOGIC_UNSIGNED.ALL;

entity counter_4bit is
    Port (
        clk   : in  STD_LOGIC;
        rst   : in  STD_LOGIC;
        en    : in  STD_LOGIC;
        count : out STD_LOGIC_VECTOR(3 downto 0)
    );
end counter_4bit;

architecture Behavioral of counter_4bit is
    signal cnt : STD_LOGIC_VECTOR(3 downto 0) := (others => '0');
begin
    process(clk, rst)
    begin
        if rst = '1' then
            cnt <= (others => '0');
        elsif rising_edge(clk) then
            if en = '1' then
                cnt <= cnt + 1;
            end if;
        end if;
    end process;
    count <= cnt;
end Behavioral;

-- ---------------------------------------------------------------
-- 5. Moore FSM: Sequence Detector (detects "101")
-- ---------------------------------------------------------------
library IEEE;
use IEEE.STD_LOGIC_1164.ALL;

entity moore_seq_detector is
    Port (
        clk    : in  STD_LOGIC;
        rst    : in  STD_LOGIC;
        x      : in  STD_LOGIC;
        detect : out STD_LOGIC
    );
end moore_seq_detector;

architecture Behavioral of moore_seq_detector is
    type state_type is (S0, S1, S2, S3);
    signal current_state, next_state : state_type;
begin
    -- State Register
    process(clk, rst)
    begin
        if rst = '1' then
            current_state <= S0;
        elsif rising_edge(clk) then
            current_state <= next_state;
        end if;
    end process;

    -- Next State Logic
    process(current_state, x)
    begin
        case current_state is
            when S0 => if x='1' then next_state<=S1; else next_state<=S0; end if;
            when S1 => if x='0' then next_state<=S2; else next_state<=S1; end if;
            when S2 => if x='1' then next_state<=S3; else next_state<=S0; end if;
            when S3 => if x='1' then next_state<=S1; else next_state<=S2; end if;
        end case;
    end process;

    -- Output Logic (Moore)
    detect <= '1' when current_state = S3 else '0';
end Behavioral;

