// ================================================================
// Verilog HDL Sequential Logic - Comprehensive Examples
// ================================================================

// ---------------------------------------------------------------
// 1. D Flip-Flop with Asynchronous Reset (Active High)
// ---------------------------------------------------------------
module dff_async_reset (
    input  wire clk,   // Clock signal
    input  wire rst,   // Asynchronous reset, active high
    input  wire d,     // Data input
    output reg  q      // Output
);
    always @(posedge clk or posedge rst) begin
        if (rst)
            q <= 1'b0;      // Reset output to 0 immediately
        else
            q <= d;         // Capture D on rising clock edge
    end
endmodule

// ---------------------------------------------------------------
// 2. D Flip-Flop with Synchronous Reset and Enable
// ---------------------------------------------------------------
module dff_sync_enable (
    input  wire clk,   // Clock
    input  wire rst,   // Synchronous reset, active high
    input  wire en,    // Clock enable
    input  wire d,     // Data input
    output reg  q      // Output
);
    always @(posedge clk) begin
        if (rst)
            q <= 1'b0;          // Synchronous reset on clock edge
        else if (en)
            q <= d;             // Load D only when enabled
        // else: q holds its value (implicit memory)
    end
endmodule

// ---------------------------------------------------------------
// 3. T Flip-Flop (Toggle)
// ---------------------------------------------------------------
module tff (
    input  wire clk,
    input  wire rst,
    input  wire t,      // Toggle input
    output reg  q
);
    always @(posedge clk or posedge rst) begin
        if (rst)
            q <= 1'b0;
        else if (t)
            q <= ~q;            // Toggle Q when T=1
        // else q holds (T=0)
    end
endmodule

// ---------------------------------------------------------------
// 4. JK Flip-Flop
// ---------------------------------------------------------------
module jkff (
    input  wire clk,
    input  wire rst,
    input  wire j,      // Set input
    input  wire k,      // Reset input
    output reg  q
);
    always @(posedge clk or posedge rst) begin
        if (rst)
            q <= 1'b0;
        else begin
            case ({j, k})
                2'b00: q <= q;      // Hold
                2'b01: q <= 1'b0;   // Reset
                2'b10: q <= 1'b1;   // Set
                2'b11: q <= ~q;     // Toggle
            endcase
        end
    end
endmodule

// ---------------------------------------------------------------
// 5. 8-bit Parallel Load Register
// ---------------------------------------------------------------
module register_8bit (
    input  wire       clk,
    input  wire       rst,
    input  wire       load,    // Load enable
    input  wire [7:0] d,       // Parallel data input
    output reg  [7:0] q        // Parallel data output
);
    always @(posedge clk or posedge rst) begin
        if (rst)
            q <= 8'b0;
        else if (load)
            q <= d;             // Load new data
        // else: hold current value
    end
endmodule

// ---------------------------------------------------------------
// 6. 4-bit Serial-In Parallel-Out (SIPO) Shift Register
// ---------------------------------------------------------------
module shift_reg_sipo (
    input  wire       clk,
    input  wire       rst,
    input  wire       sin,     // Serial input
    output reg  [3:0] pout     // Parallel output
);
    always @(posedge clk or posedge rst) begin
        if (rst)
            pout <= 4'b0;
        else
            pout <= {pout[2:0], sin}; // Shift left, insert sin at LSB
    end
endmodule

// ---------------------------------------------------------------
// 7. 4-bit Synchronous Up Counter
// ---------------------------------------------------------------
module counter_4bit (
    input  wire       clk,
    input  wire       rst,
    input  wire       en,      // Count enable
    output reg  [3:0] count
);
    always @(posedge clk or posedge rst) begin
        if (rst)
            count <= 4'b0;
        else if (en)
            count <= count + 1'b1;  // Increment by 1
    end
endmodule

// ---------------------------------------------------------------
// 8. Decade Counter (0 to 9)
// ---------------------------------------------------------------
module decade_counter (
    input  wire       clk,
    input  wire       rst,
    output reg  [3:0] count,
    output wire       tc        // Terminal count (reached 9)
);
    assign tc = (count == 4'd9) ? 1'b1 : 1'b0;

    always @(posedge clk or posedge rst) begin
        if (rst)
            count <= 4'b0;
        else if (count == 4'd9)
            count <= 4'b0;          // Reset to 0 after 9
        else
            count <= count + 1'b1;
    end
endmodule

// ---------------------------------------------------------------
// 9. Up-Down Counter with Load
// ---------------------------------------------------------------
module updown_counter (
    input  wire       clk,
    input  wire       rst,
    input  wire       load,     // Parallel load
    input  wire       up_down,  // 1=count up, 0=count down
    input  wire [3:0] d,        // Load data
    output reg  [3:0] count
);
    always @(posedge clk or posedge rst) begin
        if (rst)
            count <= 4'b0;
        else if (load)
            count <= d;
        else if (up_down)
            count <= count + 1'b1;
        else
            count <= count - 1'b1;
    end
endmodule

// ---------------------------------------------------------------
// 10. Moore FSM: Sequence Detector for "101"
//     States: S0 (idle), S1 (got 1), S2 (got 10), S3 (got 101)
// ---------------------------------------------------------------
module moore_101_detector (
    input  wire clk,
    input  wire rst,
    input  wire x,       // Serial input bit
    output reg  detect   // Output: 1 when "101" detected
);
    // State encoding
    localparam S0 = 2'b00;  // Idle / reset state
    localparam S1 = 2'b01;  // Received '1'
    localparam S2 = 2'b10;  // Received '10'
    localparam S3 = 2'b11;  // Received '101' - DETECT

    reg [1:0] current_state, next_state;

    // Block 1: State Register (Sequential)
    always @(posedge clk or posedge rst) begin
        if (rst)
            current_state <= S0;
        else
            current_state <= next_state;
    end

    // Block 2: Next-State Logic (Combinational)
    always @(*) begin
        case (current_state)
            S0: next_state = x ? S1 : S0;
            S1: next_state = x ? S1 : S2;
            S2: next_state = x ? S3 : S0;
            S3: next_state = x ? S1 : S2;  // Overlapping detection
            default: next_state = S0;
        endcase
    end

    // Block 3: Output Logic (Moore - depends only on current_state)
    always @(*) begin
        detect = (current_state == S3) ? 1'b1 : 1'b0;
    end
endmodule

// ---------------------------------------------------------------
// 11. Mealy FSM: Sequence Detector for "101"
//     (output is generated as soon as last bit arrives)
// ---------------------------------------------------------------
module mealy_101_detector (
    input  wire clk,
    input  wire rst,
    input  wire x,
    output reg  detect
);
    localparam S0 = 2'b00;
    localparam S1 = 2'b01;
    localparam S2 = 2'b10;

    reg [1:0] current_state, next_state;

    // State Register
    always @(posedge clk or posedge rst) begin
        if (rst)
            current_state <= S0;
        else
            current_state <= next_state;
    end

    // Next-State and Output Logic (Mealy: output depends on state AND input)
    always @(*) begin
        detect = 1'b0;  // Default output
        case (current_state)
            S0: begin
                    next_state = x ? S1 : S0;
                end
            S1: begin
                    next_state = x ? S1 : S2;
                end
            S2: begin
                    if (x) begin
                        next_state = S1;
                        detect = 1'b1;  // Output asserted with input in Mealy
                    end else begin
                        next_state = S0;
                    end
                end
            default: next_state = S0;
        endcase
    end
endmodule

// ---------------------------------------------------------------
// 12. Parameterized N-bit Counter
// ---------------------------------------------------------------
module counter_param #(
    parameter N = 8              // Default 8-bit counter
)(
    input  wire         clk,
    input  wire         rst,
    output reg  [N-1:0] count
);
    always @(posedge clk or posedge rst) begin
        if (rst)
            count <= {N{1'b0}};   // Reset all bits to 0
        else
            count <= count + 1'b1;
    end
endmodule

// ---------------------------------------------------------------
// 13. Traffic Light Controller FSM (Moore)
//     States: RED, GREEN, YELLOW
// ---------------------------------------------------------------
module traffic_light_fsm (
    input  wire       clk,
    input  wire       rst,
    output reg  [2:0] light   // [2]=RED, [1]=GREEN, [0]=YELLOW
);
    localparam RED    = 2'b00;
    localparam GREEN  = 2'b01;
    localparam YELLOW = 2'b10;

    reg [1:0]  current_state, next_state;
    reg [3:0]  timer;  // Timer counter

    // State register
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            current_state <= RED;
            timer <= 4'd0;
        end else begin
            current_state <= next_state;
            timer <= timer + 1'b1;
        end
    end

    // Next-state logic based on timer
    always @(*) begin
        case (current_state)
            RED:    next_state = (timer >= 4'd9)  ? GREEN  : RED;
            GREEN:  next_state = (timer >= 4'd7)  ? YELLOW : GREEN;
            YELLOW: next_state = (timer >= 4'd3)  ? RED    : YELLOW;
            default: next_state = RED;
        endcase
    end

    // Output logic
    always @(*) begin
        case (current_state)
            RED:    light = 3'b100;
            GREEN:  light = 3'b010;
            YELLOW: light = 3'b001;
            default: light = 3'b100;
        endcase
    end
endmodule

