// 4-bit Galois LFSR with feedback polynomial x^4 + x^3 + 1
// Taps at positions 4 and 3 (XOR feedback)
module lfsr_4bit (
    input  wire       clk,
    input  wire       rst,
    input  wire       en,
    output reg  [3:0] lfsr_out
);
    wire feedback;
    // Feedback from bit[3] XOR bit[2] (taps for maximal-length sequence)
    assign feedback = lfsr_out[3] ^ lfsr_out[2];

    always @(posedge clk or posedge rst) begin
        if (rst)
            lfsr_out <= 4'b0001;  // Seed (must be non-zero)
        else if (en)
            lfsr_out <= {lfsr_out[2:0], feedback}; // Shift with feedback
    end
endmodule

// Testbench
module tb_lfsr;
    reg clk, rst, en;
    wire [3:0] out;
    integer i;

    lfsr_4bit uut (.clk(clk), .rst(rst), .en(en), .lfsr_out(out));
    initial clk = 0;
    always #5 clk = ~clk;

    initial begin
        rst=1; en=0; #12;
        rst=0; en=1;
        for (i=0; i<16; i=i+1) begin
            @(posedge clk); #1;
            $display("Cycle %02d: LFSR = %b (%0d)", i, out, out);
        end
        $finish;
    end
endmodule

// Simplified APB Slave with 4 32-bit registers
// Implements full APB protocol state machine
module apb_slave_regfile #(
    parameter ADDR_WIDTH = 8,
    parameter DATA_WIDTH = 32,
    parameter NUM_REGS   = 4
)(
    // APB Interface
    input  wire                  pclk,
    input  wire                  presetn,   // Active-low async reset
    input  wire                  psel,      // Slave select
    input  wire                  penable,   // Enable phase
    input  wire                  pwrite,    // 1=write, 0=read
    input  wire [ADDR_WIDTH-1:0] paddr,     // Address
    input  wire [DATA_WIDTH-1:0] pwdata,    // Write data
    output reg  [DATA_WIDTH-1:0] prdata,    // Read data
    output reg                   pready,    // Slave ready
    output reg                   pslverr    // Slave error
);
    // APB State Machine States
    localparam IDLE    = 2'b00;
    localparam SETUP   = 2'b01;
    localparam ACCESS  = 2'b10;

    reg [1:0] apb_state, apb_next;

    // Register file: 4 x 32-bit registers
    reg [DATA_WIDTH-1:0] reg_file [0:NUM_REGS-1];
    integer idx;

    // State Register (Sequential)
    always @(posedge pclk or negedge presetn) begin
        if (!presetn) begin
            apb_state <= IDLE;
            pready    <= 1'b0;
            pslverr   <= 1'b0;
            prdata    <= {DATA_WIDTH{1'b0}};
            for (idx=0; idx<NUM_REGS; idx=idx+1)
                reg_file[idx] <= {DATA_WIDTH{1'b0}};
        end else begin
            apb_state <= apb_next;

            // Register access in ACCESS phase
            if (apb_state == ACCESS) begin
                if (pwrite) begin
                    // Write operation
                    if (paddr[3:2] < NUM_REGS)
                        reg_file[paddr[3:2]] <= pwdata;
                end else begin
                    // Read operation
                    if (paddr[3:2] < NUM_REGS)
                        prdata <= reg_file[paddr[3:2]];
                    else
                        prdata <= {DATA_WIDTH{1'b0}};
                end
                pready  <= 1'b1;
                pslverr <= (paddr[3:2] >= NUM_REGS); // Error on invalid addr
            end else begin
                pready  <= 1'b0;
                pslverr <= 1'b0;
            end
        end
    end

    // Next-State Logic (Combinational)
    always @(*) begin
        case (apb_state)
            IDLE:   apb_next = psel ? SETUP : IDLE;
            SETUP:  apb_next = (psel && penable) ? ACCESS : IDLE;
            ACCESS: apb_next = IDLE;  // Single-cycle access
            default: apb_next = IDLE;
        endcase
    end
endmodule

