module counter_2bit (
    input  wire clk, rst, en,
    output reg  [1:0] count
);
    always @(posedge clk) begin
        if (rst)
            count <= 2'b00;
        else if (en)
            count <= count + 1'b1;
    end
endmodule

// Testbench
module tb;
    reg clk=0, rst, en;
    wire [1:0] q;
    counter_2bit u(.clk(clk),.rst(rst),.en(en),.count(q));
    always #5 clk=~clk;
    initial begin
        rst=1; en=0; #12;
        rst=0; en=1; #50; // 5 clock cycles counting
        en=0; #20;        // 2 cycles hold
        en=1; #30;        // 3 more cycles
        $finish;
    end
    initial $monitor("t=%0t en=%b count=%b", $time, en, q);
endmodule

module debouncer (
    input  wire clk,       // System clock (e.g., 50MHz)
    input  wire rst,
    input  wire btn_raw,   // Bouncy button input
    output reg  btn_clean  // Debounced output
);
    // Divide 50MHz to 1kHz: 50000 cycles
    reg [15:0] div_cnt;
    reg        tick_1khz;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            div_cnt  <= 0;
            tick_1khz <= 0;
        end else if (div_cnt == 16'd49999) begin
            div_cnt   <= 0;
            tick_1khz <= 1;
        end else begin
            div_cnt   <= div_cnt + 1;
            tick_1khz <= 0;
        end
    end

    // 16-bit shift register
    reg [15:0] shift_reg;

    always @(posedge clk or posedge rst) begin
        if (rst)
            shift_reg <= 16'b0;
        else if (tick_1khz)
            shift_reg <= {shift_reg[14:0], btn_raw};
    end

    // Output: pressed only if all 16 samples are 1
    always @(posedge clk) begin
        if      (&shift_reg) btn_clean <= 1'b1;   // All 1s: pressed
        else if (~|shift_reg) btn_clean <= 1'b0;  // All 0s: released
        // else: hold current state (hysteresis)
    end
endmodule

module seq_0110 (
    input  wire clk, rst, x,
    output reg  detect
);
    localparam S0=3'd0, S1=3'd1, S2=3'd2,
               S3=3'd3, S4=3'd4;
    reg [2:0] state, next;

    // Sequential: state register
    always @(posedge clk or posedge rst)
        state <= rst ? S0 : next;

    // Combinational: next-state logic
    always @(*) begin
        case (state)
            S0: next = x ? S0 : S1;
            S1: next = x ? S2 : S1;
            S2: next = x ? S3 : S1;
            S3: next = x ? S0 : S4;
            S4: next = S0;        // Non-overlapping: always back to S0
            default: next = S0;
        endcase
    end

    // Output logic (Moore)
    always @(*)
        detect = (state == S4) ? 1'b1 : 1'b0;
endmodule

